document.addEventListener("DOMContentLoaded",(function(){document.querySelectorAll(".checkbox-class").forEach((e=>{const t=e.getAttribute("data-related-select"),d=e.getAttribute("data-related-select1"),l=e.getAttribute("data-related-select2"),n=e.getAttribute("data-related-text"),a=e.getAttribute("data-related-date"),u=e.getAttribute("data-related-date1"),c=e.getAttribute("data-related-date2"),r=e.getAttribute("data-related-number1"),m=e.getAttribute("data-related-number2"),o={select:t?document.getElementById(t):null,select1:t?document.getElementById(d):null,select2:t?document.getElementById(l):null,text:n?document.getElementById(n):null,date:a?document.getElementById(a):null,date1:u?document.getElementById(u):null,date2:c?document.getElementById(c):null,number1:r?document.getElementById(r):null,number2:m?document.getElementById(m):null};function updateElements(){Object.keys(o).forEach((t=>{const d=o[t];d&&(d.disabled=!e.checked,e.checked||(d.value=""))}))}e.addEventListener("change",updateElements),updateElements()}))}));